<?php
namespace Database\Seeders;use App\Models\SecurityIncidentPlaybook;use Illuminate\Database\Seeder;
class SecurityIncidentPlaybookSeeder extends Seeder{public function run():void{$items=['unauthorized_audit_export_download'=>['Verify actor and route','Confirm permission state','Review audit export download events','Confirm no file leak','Assign owner in-app','Resolve or escalate'],'scan_unavailable_private_evidence'=>['Verify scanner setting','Confirm evidence scan status','Block reviewer download','Decide owner override or scanner setup','Document risk acceptance'],'overdue_governance_review'=>['Identify overdue cycle','Assign owner','Run SLA check','Create or resolve incident','Update access review cycle'],'retention_execution_blocked'=>['Verify dry-run-only settings','Verify deletion disabled','Confirm no files deleted','Document policy decision']];foreach($items as $key=>$steps)SecurityIncidentPlaybook::updateOrCreate(['playbook_key'=>$key],['name'=>str($key)->replace('_',' ')->title(),'description'=>'Governed security response playbook.','is_active'=>true,'steps'=>$steps]);}}
